/**
 * search.js — Article search modal.
 *
 * Fetches /index.json (generated by Hugo from all digest posts), scores
 * results by word overlap, and renders a modal with pillar-colored badges.
 * Click a result → navigates to the digest page with the matching category
 * section in the URL hash (collapsible.js auto-opens it on arrival).
 *
 * Keyboard shortcuts:
 *   /         — open modal (when not in an input)
 *   Ctrl + K  — open modal
 *   Escape    — close modal
 */

(function () {
  'use strict';

  var INDEX_URL = '/search.json';
  var searchIndex = null;

  // Category name → accent color (matches PILLAR_COLORS in collapsible.js)
  var CAT_COLORS = [
    { keys: ['visibility', 'automation', 'ai'],   color: '#d2a8ff' },
    { keys: ['collaboration', 'productivity'],     color: '#58a6ff' },
    { keys: ['identity', 'access'],                color: '#a78bfa' },
    { keys: ['endpoint', 'devices'],               color: '#3fb950' },
    { keys: ['security', 'compliance', 'data'],    color: '#f0883e' },
    { keys: ['network'],                           color: '#39d353' },
    { keys: ['apps'],                              color: '#58a6ff' },
    { keys: ['action', 'required', 'recommended'], color: '#ff6b6b' },
  ];

  function categoryColor(cat) {
    var c = (cat || '').toLowerCase();
    for (var i = 0; i < CAT_COLORS.length; i++) {
      for (var j = 0; j < CAT_COLORS[i].keys.length; j++) {
        if (c.indexOf(CAT_COLORS[i].keys[j]) !== -1) return CAT_COLORS[i].color;
      }
    }
    return '#6e7681';
  }

  // Produce the same heading slug Hugo/goldmark generates from a category name.
  // e.g. "Security & Compliance" → "security--compliance"
  function toSectionSlug(text) {
    return (text || '').toLowerCase()
      .replace(/\s+/g, '-')           // spaces → dashes
      .replace(/[^a-z0-9\-_]/g, '')  // remove non-alnum/-/_
      .replace(/^-+|-+$/g, '');       // trim edges
  }

  // Score an article against the query words (title weighted highest)
  function scoreItem(item, words) {
    var s    = 0;
    var t    = (item.title    || '').toLowerCase();
    var cat  = (item.category || '').toLowerCase();
    var snip = (item.snippet  || '').toLowerCase();
    words.forEach(function (w) {
      if (!w) return;
      if (t.indexOf(w)    !== -1) s += 5;
      if (cat.indexOf(w)  !== -1) s += 2;
      if (snip.indexOf(w) !== -1) s += 1;
    });
    return s;
  }

  function runSearch(query) {
    if (!searchIndex || !query.trim()) return [];
    var words = query.toLowerCase().split(/\s+/).filter(Boolean);
    return searchIndex
      .map(function (item) { return { item: item, score: scoreItem(item, words) }; })
      .filter(function (r) { return r.score > 0; })
      .sort(function (a, b) { return b.score - a.score; })
      .slice(0, 18)
      .map(function (r) { return r.item; });
  }

  function esc(s) {
    return String(s)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  function renderResults(results, query) {
    var el = document.getElementById('search-results');
    if (!el) return;
    if (!query.trim()) { el.innerHTML = ''; return; }

    if (!results.length) {
      el.innerHTML = '<div class="search-empty">No results for <em>' + esc(query) + '</em></div>';
      return;
    }

    el.innerHTML = results.map(function (r) {
      var color   = categoryColor(r.category);
      var slug    = toSectionSlug(r.category || '');
      var href    = esc(r.url + (slug ? '#' + slug : ''));
      var snippet = (r.snippet || '').slice(0, 180);
      // Readable date: "2026-05-20" → "May 20, 2026"
      var dateParts = (r.date || '').split('-');
      var dateLabel = r.date || '';
      if (dateParts.length === 3) {
        var months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
        var m = parseInt(dateParts[1], 10) - 1;
        dateLabel = months[m] + ' ' + parseInt(dateParts[2], 10) + ', ' + dateParts[0];
      }
      return '<a href="' + href + '" class="search-result">' +
        '<div class="search-result-title">' + esc(r.title) + '</div>' +
        '<div class="search-result-meta">' +
          '<span class="search-result-cat" style="background:' + color + '">' + esc(r.category || '') + '</span>' +
          '<span class="search-result-date">' + esc(dateLabel) + '</span>' +
        '</div>' +
        (snippet ? '<div class="search-result-snippet">' + esc(snippet) + '</div>' : '') +
      '</a>';
    }).join('');
  }

  function openModal() {
    var overlay = document.getElementById('search-overlay');
    if (!overlay) return;
    overlay.classList.add('is-open');
    document.body.style.overflow = 'hidden';
    var input = document.getElementById('search-input');
    if (input) { input.value = ''; input.focus(); }
    var results = document.getElementById('search-results');
    if (results) results.innerHTML = '';
    // Lazy-load index on first open. Cache-bust so Cloudflare doesn't serve
    // a stale /index.json from a previous deploy.
    if (!searchIndex) {
      var resultsEl2 = document.getElementById('search-results');
      if (resultsEl2) resultsEl2.innerHTML = '<div class="search-empty search-loading">Loading index…</div>';
      fetch(INDEX_URL + '?v=' + (window._siteBuildTime || Date.now()), { cache: 'no-store' })
        .then(function (r) {
          if (!r.ok) throw new Error('HTTP ' + r.status + ' fetching ' + INDEX_URL);
          return r.json();
        })
        .then(function (data) {
          searchIndex = Array.isArray(data) ? data : [];
          if (resultsEl2) resultsEl2.innerHTML = '';
        })
        .catch(function (err) {
          console.error('[search] Could not load search index:', err);
          searchIndex = [];
          if (resultsEl2) {
            resultsEl2.innerHTML = '<div class="search-empty search-error">⚠ Search index unavailable — try reloading the page.<br><small>' + err.message + '</small></div>';
          }
        });
    }
  }

  function closeModal() {
    var overlay = document.getElementById('search-overlay');
    if (overlay) overlay.classList.remove('is-open');
    document.body.style.overflow = '';
  }

  document.addEventListener('DOMContentLoaded', function () {
    // Trigger button(s)
    document.querySelectorAll('.search-btn').forEach(function (btn) {
      btn.addEventListener('click', openModal);
    });

    // Click outside the box → close
    var overlay = document.getElementById('search-overlay');
    if (overlay) {
      overlay.addEventListener('click', function (e) {
        if (e.target === overlay) closeModal();
      });
    }

    // Keyboard shortcuts
    document.addEventListener('keydown', function (e) {
      if (e.key === 'Escape') { closeModal(); return; }
      var inInput = ['INPUT', 'TEXTAREA', 'SELECT'].indexOf(document.activeElement.tagName) !== -1;
      if (!inInput && e.key === '/') { e.preventDefault(); openModal(); }
      if (e.key === 'k' && (e.ctrlKey || e.metaKey)) { e.preventDefault(); openModal(); }
    });

    // Live search as user types
    var input = document.getElementById('search-input');
    if (input) {
      input.addEventListener('input', function () {
        renderResults(runSearch(this.value), this.value);
      });
    }

    // Click a result → close modal and navigate
    var resultsEl = document.getElementById('search-results');
    if (resultsEl) {
      resultsEl.addEventListener('click', function () { closeModal(); });
    }
  });
})();
